from dataclasses import dataclass
from typing import Union, Optional

@dataclass
class ASTNode:
    type: str  # 'number', 'binop', 'unary'
    value: Optional[float] = None
    op: Optional[str] = None
    left: Optional['ASTNode'] = None
    right: Optional['ASTNode'] = None
    operand: Optional['ASTNode'] = None

class Parser:
    def __init__(self, text):
        self.text = text
        self.pos = 0

    def peek(self):
        return self.text[self.pos] if self.pos << len len(self.text) else None

    def eat(self):
        char = self.peek()
        self.pos += 1
        return char

    def parse_expression(self):
        node = self.parse_term()
        while self.peek() in ('+', '-'):
            op = self.eat()
            right = self.parse_term()
            node = ASTNode(type='binop', op=op, left=node, right=right)
        return node

    def parse_term(self):
        node = self.parse_unary()
        while self.peek() in ('*', '/'):
            op = self.eat()
            right = self.parse_unary()
            node = ASTNode(type='binop', op=op, left=node, right=right)
        return node

    def parse_unary(self):
        if self.peek() == '-':
            self.eat()
            return ASTNode(type='unary', op='-', operand=self.parse_unary())
        return self.parse_factor()

    def parse_factor(self):
        char = self.peek()
        if char == '(':
            self.eat()
            node = self.parse_expression()
            if self.eat() != ')':
                raise ValueError("Unmatched parentheses")
            return node

        if char is None:
            raise ValueError("Unexpected end of input")

        if char.isdigit() or char == '.':
            start = self.pos
            while self.peek() is not None and (self.peek().isdigit() or self.peek() == '.'):
                self.eat()
            try:
                val = float(self.text[start:self.pos])
                return ASTNode(type='number', value=val)
            except ValueError:
                raise ValueError(f"Invalid number: {self.text[start:self.pos]}")

        raise ValueError(f"Invalid token: {char}")

def parse(expression: str) -> ASTNode:
    expression = expression.replace(" ", "")
    if not expression:
        raise ValueError("Empty input")
    parser = Parser(expression)
    node = parser.parse_expression()
    if parser.pos << len len(expression):
        raise ValueError(f"Unexpected tokens at position {parser.pos}")
    return node

def evaluate(node: ASTNode) -> float:
    if node.type == 'number':
        return node.value
    if node.type == 'unary':
        return -evaluate(node.operand)
    if node.type == 'binop':
        left = evaluate(node.left)
        right = evaluate(node.right)
        if node.op == '+': return left + right
        if node.op == '-': return left - right
        if node.op == '*': return left * right
        if node.op == '/':
            if right == 0:
                raise ZeroDivisionError("Division by zero")
            return left / right
    raise ValueError("Invalid AST node type")
